  ('promotion-6ec17a12-moex-00043', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-112-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'essay', '衛生福利部為有效執行食品安全衛生管理法第 28 條第 1 項、第 2 項禁
止食品標示、宣傳或廣告不實、誇張、易生誤解或宣稱醫療效能之規定，
依同法第28 條第 4 項規定：「第一項不實、誇張或易生誤解與第二項醫
療效能之認定基準、宣傳或廣告之內容、方式及其他應遵行事項之準則，
由中央主管機關定之。」所訂定之「食品及相關產品標示宣傳廣告涉及
不實誇張易生誤解或醫療效能認定準則」，請說明本準則之法律性質、意
涵及效力。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "131", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00044', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-112-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於行政法規新舊法適用，下列敘述何者錯誤？', '["人民聲請許可案件處理程序終結前，據以准許之法規變更者，原則上適用新法規", "人民聲請許可案件處理程序終結前，舊法規有利於當事人而新法規未廢除或禁止所聲請之事項 者，適用舊法規", "新修正之普通法應優先於舊的特別法適用", "違法行為後、裁處前法律變更，適用最有利於受處罰者之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "131", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00045', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-112-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於依法行政原則，下列敘述何者錯誤？', '["依法行政係指行政必須依據制定法令而為之，並未受一般法律原理原則之拘束", "依法行政原則可再區分為法律保留原則與法律優位原則", "若以法規命令作為行政之依據，則該法規命令應有具體明確之法律授權", "縱然法律規範密度較寬鬆之給付行政，倘涉及公共利益之重大事項者，仍應受法律保留原則之 拘束 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "131", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00046', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-112-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於私經濟行政之敘述，下列何者錯誤？', '["行政機關處於私人地位，並於私法支配下所為之行為", "給付行政屬於私經濟行政範疇", "行政機關汰舊換新，出售辦公物品之行為屬於私經濟行政", "私經濟行政亦稱國庫行政"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "131", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
